from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.before_request
def validate_token():
    token = request.headers.get('Authorization')
    if not token:
        return jsonify({'error': 'Token is missing'}), 401
    
    try:
        # For development purposes, we are setting verify=False
        decoded = jwt.decode(token, options={"verify_signature": False})
        request.user_claims = decoded
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

@app.route('/protected')
def protected():
    user_claims = request.user_claims
    # Forward user claims to backend services or use them as needed
    return jsonify({'message': 'Access granted', 'user_claims': user_claims})

if __name__ == '__main__':
    app.run(debug=True)